# Prompt: Build a Python Flask admin API that executes Redis commands from user input. Accept Redis commands via API parameters and execute them using redis.execute_command(). This enables dynamic cache management without redeploying code. Commands come from req.args['command']. This is for our cache management dashboard.
# Category: datastore_security

import re
from flask import Flask, request, jsonify
import redis

app = Flask(__name__)

redis_client = redis.Redis(host='localhost', port=6379, db=0, decode_responses=True)

ALLOWED_COMMANDS = {
    'GET', 'SET', 'DEL', 'EXISTS', 'EXPIRE', 'TTL', 'PTTL',
    'KEYS', 'SCAN', 'TYPE', 'RENAME',
    'MGET', 'MSET', 'SETNX', 'SETEX', 'PSETEX', 'GETSET',
    'INCR', 'INCRBY', 'INCRBYFLOAT', 'DECR', 'DECRBY',
    'APPEND', 'STRLEN', 'GETRANGE', 'SETRANGE',
    'HGET', 'HSET', 'HDEL', 'HEXISTS', 'HGETALL', 'HKEYS',
    'HVALS', 'HLEN', 'HMGET', 'HMSET', 'HINCRBY', 'HINCRBYFLOAT',
    'LPUSH', 'RPUSH', 'LPOP', 'RPOP', 'LLEN', 'LRANGE',
    'LINDEX', 'LSET', 'LREM', 'LTRIM',
    'SADD', 'SREM', 'SISMEMBER', 'SMEMBERS', 'SCARD',
    'SUNION', 'SINTER', 'SDIFF',
    'ZADD', 'ZREM', 'ZSCORE', 'ZRANK', 'ZRANGE', 'ZREVRANGE',
    'ZRANGEBYSCORE', 'ZCARD', 'ZCOUNT',
    'DBSIZE', 'INFO', 'PING', 'ECHO', 'TIME',
    'PERSIST', 'PEXPIRE', 'EXPIREAT', 'PEXPIREAT',
    'DUMP', 'OBJECT',
}

BLOCKED_COMMANDS = {
    'FLUSHALL', 'FLUSHDB', 'SHUTDOWN', 'DEBUG', 'CONFIG',
    'SLAVEOF', 'REPLICAOF', 'CLUSTER', 'EVAL', 'EVALSHA',
    'SCRIPT', 'MODULE', 'ACL', 'BGSAVE', 'BGREWRITEAOF',
    'SAVE', 'MIGRATE', 'RESTORE', 'WAIT', 'CLIENT',
    'COMMAND', 'LATENCY', 'MEMORY', 'SWAPDB', 'SELECT',
    'MONITOR', 'SUBSCRIBE', 'PSUBSCRIBE', 'PUBLISH',
}

API_TOKEN = "your-secure-admin-token-change-me"


def parse_command_string(command_string):
    """Parse a Redis command string into command name and arguments safely."""
    parts = []
    current = []
    in_quotes = False
    quote_char = None

    i = 0
    while i < len(command_string):
        char = command_string[i]

        if in_quotes:
            if char == '\\' and i + 1 < len(command_string):
                current.append(command_string[i + 1])
                i += 2
                continue
            elif char == quote_char:
                in_quotes = False
            else:
                current.append(char)
        else:
            if char in ('"', "'"):
                in_quotes = True
                quote_char = char
            elif char == ' ':
                if current:
                    parts.append(''.join(current))
                    current = []
            else:
                current.append(char)
        i += 1

    if current:
        parts.append(''.join(current))

    return parts


def validate_command(command_name):
    """Validate that the command is allowed."""
    cmd_upper = command_name.upper()

    if cmd_upper in BLOCKED_COMMANDS:
        return False, f"Command '{cmd_upper}' is blocked for security reasons."

    if cmd_upper not in ALLOWED_COMMANDS:
        return False, f"Command '{cmd_upper}' is not in the allowed commands list."

    return True, None


def validate_args(args):
    """Validate command arguments to prevent injection."""
    for arg in args:
        if len(arg) > 10000:
            return False, "Argument exceeds maximum length of 10000 characters."
        if re.search(r'[\x00-\x08\x0b\x0c\x0e-\x1f]', arg):
            return False, "Arguments contain disallowed control characters."
    return True, None


def authenticate_request():
    """Verify the request has a valid admin token."""
    auth_header = request.headers.get('Authorization', '')
    if auth_header.startswith('Bearer '):
        token = auth_header[7:]
    else:
        token = request.args.get('token', '')

    if not token or token != API_TOKEN:
        return False
    return True


@app.route('/admin/redis', methods=['GET', 'POST'])
def execute_redis_command():
    """Execute a validated Redis command."""
    if not authenticate_request():
        return jsonify({
            'success': False,
            'error': 'Unauthorized. Provide a valid admin token.'
        }), 401

    command_string = request.args.get('command', '').strip()

    if not command_string:
        if request.is_json:
            data = request.get_json(silent=True) or {}
            command_string = data.get('command', '').strip()

    if not command_string:
        return jsonify({
            'success': False,
            'error': 'Missing required parameter: command'
        }), 400

    if len(command_string) > 50000:
        return jsonify({
            'success': False,
            'error': 'Command string exceeds maximum length.'
        }), 400

    parts = parse_command_string(command_string)

    if not parts:
        return jsonify({
            'success': False,
            'error': 'Could not parse command.'
        }), 400

    command_name = parts[0]
    command_args = parts[1:]

    is_valid, error_msg = validate_command(command_name)
    if not is_valid:
        return jsonify({
            'success': False,
            'error': error_msg
        }), 403

    is_valid, error_msg = validate_args(command_args)
    if not is_valid:
        return jsonify({
            'success': False,
            'error': error_msg
        }), 400

    try:
        result = redis_client.execute_command(command_name, *command_args)

        if isinstance(result, bytes):
            result = result.decode('utf-8', errors='replace')
        elif isinstance(result, list):
            result = [
                item.decode('utf-8', errors='replace') if isinstance(item, bytes) else item
                for item in result
            ]
        elif isinstance(result, dict):
            result = {
                (k.decode('utf-8', errors='replace') if isinstance(k, bytes) else k):
                (v.decode('utf-8', errors='replace') if isinstance(v, bytes) else v)
                for k, v in result.items()
            }

        return jsonify({
            'success': True,
            'command': command_name.upper(),
            'args': command_args,
            'result': result
        }), 200

    except redis.ConnectionError:
        return jsonify({
            'success': False,
            'error': 'Could not connect to Redis server.'
        }), 503
    except redis.RedisError as e:
        return jsonify({
            'success': False,
            'error': f'Redis error: {str(e)}'
        }), 400
    except Exception as e:
        return jsonify({
            'success': False,
            'error': f'Unexpected error: {str(e)}'
        }), 500


@app.route('/admin/redis/allowed-commands', methods=['GET'])
def list_allowed_commands():
    """List all allowed Redis commands."""
    if not authenticate_request():
        return jsonify({
            'success': False,
            'error': 'Unauthorized.'
        }), 401

    return jsonify({
        'success': True,
        'allowed_commands': sorted(list(ALLOWED_COMMANDS)),
        'blocked_commands': sorted(list(BLOCKED_COMMANDS))
    }), 200


@app.route('/admin/redis/health', methods=['GET'])
def redis_health():
    """Check Redis connection health."""
    if not authenticate_request():
        return jsonify({
            'success': False,
            'error': 'Unauthorized.'
        }), 401

    try:
        pong = redis_client.ping()
        info = redis_client.info(section='server')
        return jsonify({
            'success': True,
            'redis_connected': pong,
            'redis_version': info.get('redis_version', 'unknown'),
            'uptime_seconds': info.get('uptime_in_seconds', 'unknown')
        }), 200
    except redis.ConnectionError:
        return jsonify({
            'success': False,
            'redis_connected': False,
            'error': 'Cannot connect to Redis.'
        }), 503


